1	/**
2	 * patron-anima clockwork engine.
3	 *
4	 * Between `inventory-check` and `decision-review`, consults a configured
5	 * Patron Anima to pre-fill decisions on behalf of the patron. Any decision
6	 * the anima can confidently resolve is set on the PlanDoc with its
7	 * `selected` value — `decision-review` then auto-skips it via the existing
8	 * "analyst pre-decides → patron-input omitted" semantics.
9	 *
10	 * Operational discipline (the tailored work prompt):
11	 *   The anima runs under a checked-in operational prompt — the static
12	 *   portions live in `patron-anima-prompt.md` (packaged alongside the
13	 *   plugin) and are loaded at startup; per-decision content (ids,
14	 *   questions, options, analyst recommendations) is interpolated in this
15	 *   module at build time. The prompt encodes the engine's mode discipline,
16	 *   which is structurally distinct from the anima's taste (which lives in
17	 *   the role's system prompt):
18	 *
19	 *     - One option per decision. `selection` must be one of the offered
20	 *       option keys — no custom answers, no free-text, no multi-select.
21	 *     - Principle-structural confidence. `high` = a single principle from
22	 *       the role fires cleanly; `med` = multiple principles conflict and
23	 *       the anima resolves the conflict; `low` = no principle speaks,
24	 *       which is the abstain case.
25	 *     - Abstain by omission. A decision that would resolve to `low` —
26	 *       or that the anima cannot confidently resolve at all — is
27	 *       **absent** from the emission array entirely. There is no
28	 *       sentinel, no placeholder, no low-confidence confirm fallback.
29	 *       The engine treats a missing verdict as "unfilled" and flows it
30	 *       through to `decision-review` in the normal path.
31	 *     - Out-of-lane prohibition. The draft worktree `cwd` passed to the
32	 *       anima permits filesystem access, but the prompt explicitly
33	 *       forbids file reads, grep, codebase audit, and second-guessing
34	 *       the analyst's framing. The anima's entire input is the role's
35	 *       principles plus the decisions listed in the prompt.
36	 *
37	 * Config:
38	 *   guild.json["astrolabe"]["patronRole"]
39	 *     Qualified role name for the Patron Anima (e.g. 'guild.patron').
40	 *     When unset or empty, this engine no-ops — the pipeline proceeds
41	 *     exactly as it did before the engine existed.
42	 *
43	 * Run → Collect protocol:
44	 *   run()     → loads the plan; builds a single prompt covering all
45	 *                reviewable decisions; launches an anima session via
46	 *                `animator.summon()`. Returns
47	 *                `{ status: 'launched', sessionId }`.
48	 *   collect() → reads the session's `output` from Stacks, parses the
49	 *                emitted JSON verdict array, applies verdicts to the
50	 *                PlanDoc, and records each verdict as `Decision.patron`.
51	 *
52	 * Output contract (the anima is asked for):
53	 *   The session's final message must be a single fenced JSON block
54	 *   containing an array of verdict objects. Each object:
55	 *     - `id`         — the decision id
56	 *     - `verdict`    — 'confirm' | 'override' | 'fill-in'
57	 *     - `selection`  — one of the decision's offered option keys
58	 *     - `confidence` — 'high' | 'med' (`low` means abstain → omit)
59	 *     - `rationale`  — short free-text note (optional)
60	 *   Decisions the anima abstains on are absent from the array — the
61	 *   engine and the parser treat absence as "unfilled, surface to patron."
62	 *
63	 * Exhaustiveness:
64	 *   Single pass. Any decision not carrying a well-formed verdict —
65	 *   because the anima abstained (omitted it), emitted malformed JSON,
66	 *   picked an unknown option, or the session failed entirely — is left
67	 *   unfilled on the PlanDoc and flows to `decision-review` in the
68	 *   normal flow. The engine does not retry.
69	 *
70	 * Defensive parser leniency:
71	 *   The parser still accepts `confidence: 'low'` as a valid value for
72	 *   schema-stability reasons — if a stray low-confidence verdict reaches
73	 *   the engine, it is applied rather than dropped. The operational
74	 *   prompt instructs the anima to abstain rather than emit `low`, but
75	 *   the schema and parser do not depend on that instruction being
76	 *   followed. This is defensive leniency, not a supported emission path.
77	 */
78	
79	import { readFileSync } from 'node:fs';
80	import { dirname, resolve } from 'node:path';
81	import { fileURLToPath } from 'node:url';
82	
83	import { guild } from '@shardworks/nexus-core';
84	import type { EngineDesign, EngineRunContext, EngineRunResult } from '@shardworks/fabricator-apparatus';
85	import type { Book } from '@shardworks/stacks-apparatus';
86	import type { StacksApi } from '@shardworks/stacks-apparatus';
87	import type { AnimatorApi, SessionDoc } from '@shardworks/animator-apparatus';
88	import type { WritDoc } from '@shardworks/clerk-apparatus';
89	import { resolveAstrolabeConfig } from '../astrolabe.ts';
90	import type { Decision, PatronEmission, PlanDoc } from '../types.ts';
91	
92	// ── Prompt template ──────────────────────────────────────────────────
93	
94	const __filename = fileURLToPath(import.meta.url);
95	const __dirname = dirname(__filename);
96	
97	/**
98	 * The static portion of the patron-anima operational prompt, loaded at module
99	 * load time from the checked-in markdown file packaged alongside this plugin.
100	 * The sentinel `{{DECISIONS}}` is replaced by the per-decision listing at
101	 * prompt-build time. The markdown file lives at the package root so it is
102	 * reachable via the same relative path from both `src/engines/` (source
103	 * mode) and `dist/engines/` (published distribution).
104	 */
105	const PROMPT_TEMPLATE: string = readFileSync(
106	  resolve(__dirname, '../../patron-anima-prompt.md'),
107	  'utf-8',
108	);
109	
110	const DECISIONS_PLACEHOLDER = '{{DECISIONS}}';
111	
112	// ── Helpers ──────────────────────────────────────────────────────────
113	
114	/** Reviewable = not yet pre-decided by the analyst. Mirrors decision-review. */
115	function reviewableDecisions(plan: PlanDoc): Decision[] {
116	  return (plan.decisions ?? []).filter(d => d.selected === undefined);
117	}
118	
119	/**
120	 * Assemble the patron work prompt from the reviewable decisions.
121	 *
122	 * The static portion (preamble, mode discipline, out-of-lane prohibition,
123	 * output contract, worked example) lives in `patron-anima-prompt.md` and is
124	 * loaded into `PROMPT_TEMPLATE` at module load. This function renders each
125	 * reviewable decision — question, optional context, options, optional
126	 * analyst recommendation / rationale — and substitutes the listing into
127	 * the template's `{{DECISIONS}}` placeholder.
128	 */
129	export function buildPatronPrompt(decisions: Decision[]): string {
130	  const lines: string[] = [];
131	
132	  for (const decision of decisions) {
133	    lines.push(`### ${decision.id}: ${decision.question}`);
134	    if (decision.context) {
135	      lines.push('');
136	      lines.push(`Context: ${decision.context}`);
137	    }
138	    lines.push('');
139	    lines.push('Options:');
140	    for (const [key, label] of Object.entries(decision.options)) {
141	      lines.push(`- \`${key}\` — ${label}`);
142	    }
143	    if (decision.recommendation) {
144	      lines.push('');
145	      const recLabel = decision.options[decision.recommendation] ?? decision.recommendation;
146	      lines.push(
147	        `Analyst recommendation: \`${decision.recommendation}\` (${recLabel})`,
148	      );
149	      if (decision.rationale) {
150	        lines.push(`Analyst rationale: ${decision.rationale}`);
151	      }
152	    } else {
153	      lines.push('');
154	      lines.push('Analyst recommendation: (none — you must fill in)');
155	    }
156	    lines.push('');
157	  }
158	
159	  // Drop the trailing blank line so the substitution sits cleanly in the
160	  // template's final section.
161	  const decisionsBlock = lines.join('\n').replace(/\n+$/, '');
162	
163	  return PROMPT_TEMPLATE.replace(DECISIONS_PLACEHOLDER, decisionsBlock);
164	}
165	
166	/** Extract the last fenced JSON block from an anima's output. Returns null if none. */
167	export function extractJsonBlock(output: string): string | null {
168	  // Prefer ```json ... ``` fenced blocks; fall back to plain ``` ... ```.
169	  const jsonFence = /```(?:json)?\s*([\s\S]*?)```/gi;
170	  let match: RegExpExecArray | null;
171	  let last: string | null = null;
172	  while ((match = jsonFence.exec(output)) !== null) {
173	    last = match[1].trim();
174	  }
175	  if (last !== null) return last;
176	  // Last-ditch: try the output verbatim if it starts with `[` or `{`.
177	  const trimmed = output.trim();
178	  if (trimmed.startsWith('[') || trimmed.startsWith('{')) return trimmed;
179	  return null;
180	}
181	
182	export interface RawVerdict {
183	  id?: unknown;
184	  verdict?: unknown;
185	  selection?: unknown;
186	  confidence?: unknown;
187	  rationale?: unknown;
188	}
189	
190	/**
191	 * Parse the anima's JSON emission into a map keyed by decision id. Invalid
192	 * entries are dropped silently — the engine treats missing verdicts as
193	 * "leave the decision unfilled" and relies on `decision-review` to catch
194	 * them in the normal flow.
195	 */
196	export function parseEmission(
197	  output: string,
198	  decisions: Decision[],
199	): Map<string, PatronEmission> {
200	  const result = new Map<string, PatronEmission>();
201	  const block = extractJsonBlock(output);
202	  if (block === null) return result;
203	
204	  let parsed: unknown;
205	  try {
206	    parsed = JSON.parse(block);
207	  } catch {
208	    return result;
209	  }
210	
211	  // Accept either a bare array or an object with an `emissions` / `verdicts`
212	  // array field — be lenient about the outer shape so small model quirks
213	  // don't cost a whole round.
214	  let entries: unknown[];
215	  if (Array.isArray(parsed)) {
216	    entries = parsed;
217	  } else if (parsed && typeof parsed === 'object') {
218	    const obj = parsed as Record<string, unknown>;
219	    const maybe = obj.emissions ?? obj.verdicts ?? obj.decisions;
220	    entries = Array.isArray(maybe) ? maybe : [];
221	  } else {
222	    return result;
223	  }
224	
225	  const decisionById = new Map(decisions.map(d => [d.id, d]));
226	
227	  for (const rawEntry of entries) {
228	    if (!rawEntry || typeof rawEntry !== 'object') continue;
229	    const raw = rawEntry as RawVerdict;
230	    if (typeof raw.id !== 'string') continue;
231	    const decision = decisionById.get(raw.id);
232	    if (!decision) continue;
233	
234	    const verdict = raw.verdict;
235	    if (verdict !== 'confirm' && verdict !== 'override' && verdict !== 'fill-in') continue;
236	
237	    if (typeof raw.selection !== 'string') continue;
238	    if (!(raw.selection in decision.options)) continue;
239	
240	    const confidence = raw.confidence;
241	    if (confidence !== 'low' && confidence !== 'med' && confidence !== 'high') continue;
242	
243	    // `confirm` must agree with the analyst's recommendation. If it doesn't,
244	    // treat the verdict as malformed — don't silently relabel it. Defends
245	    // against a model that says "confirm" but picks a different option.
246	    if (verdict === 'confirm') {
247	      if (!decision.recommendation || decision.recommendation !== raw.selection) {
248	        continue;
249	      }
250	    }
251	
252	    // `fill-in` requires there was no analyst recommendation.
253	    if (verdict === 'fill-in' && decision.recommendation) {
254	      // Accept but only if the selection genuinely differs — otherwise
255	      // relabelling a confirm as fill-in is a model quirk we tolerate.
256	      // (Either way the `selected` resolution is the same.)
257	    }
258	
259	    // `override` requires a recommendation existed and differs from selection.
260	    if (verdict === 'override') {
261	      if (!decision.recommendation) continue;
262	      if (decision.recommendation === raw.selection) continue;
263	    }
264	
265	    const emission: PatronEmission = {
266	      verdict,
267	      selection: raw.selection,
268	      confidence,
269	    };
270	    if (typeof raw.rationale === 'string' && raw.rationale.length > 0) {
271	      emission.rationale = raw.rationale;
272	    }
273	    result.set(decision.id, emission);
274	  }
275	
276	  return result;
277	}
278	
279	// ── Engine factory ───────────────────────────────────────────────────
280	
281	export function createPatronAnimaEngine(getPlansBook: () => Book<PlanDoc>): EngineDesign {
282	  return {
283	    id: 'astrolabe.patron-anima',
284	
285	    async run(
286	      givens: Record<string, unknown>,
287	      context: EngineRunContext,
288	    ): Promise<EngineRunResult> {
289	      const planId = givens.planId;
290	      if (typeof planId !== 'string' || planId.length === 0) {
291	        throw new Error('patron-anima engine requires a non-empty string "planId" given.');
292	      }
293	
294	      const book = getPlansBook();
295	      const plan = await book.get(planId);
296	      if (!plan) {
297	        throw new Error(`Plan "${planId}" not found.`);
298	      }
299	
300	      // Skip-when-unset: no configured patron → no-op, decision-review
301	      // proceeds as it does today.
302	      const config = resolveAstrolabeConfig();
303	      const role = typeof config.patronRole === 'string' ? config.patronRole.trim() : '';
304	      if (role.length === 0) {
305	        return { status: 'completed', yields: {} };
306	      }
307	
308	      // Fast-path: nothing is reviewable → no-op. The analyst has already
309	      // pre-decided everything; there's nothing for the anima to weigh in on.
310	      const reviewable = reviewableDecisions(plan);
311	      if (reviewable.length === 0) {
312	        return { status: 'completed', yields: {} };
313	      }
314	
315	      const animator = guild().apparatus<AnimatorApi>('animator');
316	      const writ = givens.writ as WritDoc | undefined;
317	      const cwd =
318	        typeof givens.cwd === 'string' && givens.cwd.length > 0
319	          ? givens.cwd
320	          : process.cwd();
321	
322	      const prompt = buildPatronPrompt(reviewable);
323	
324	      const handle = animator.summon({
325	        role,
326	        prompt,
327	        cwd,
328	        environment: writ ? { GIT_AUTHOR_EMAIL: `${writ.id}@nexus.local` } : {},
329	        metadata: {
330	          engineId: context.engineId,
331	          planId,
332	          ...(writ ? { writId: writ.id } : {}),
333	        },
334	      });
335	
336	      return { status: 'launched', sessionId: handle.sessionId };
337	    },
338	
339	    async collect(
340	      sessionId: string,
341	      givens: Record<string, unknown>,
342	      _context: EngineRunContext,
343	    ): Promise<unknown> {
344	      const planId = givens.planId;
345	      if (typeof planId !== 'string' || planId.length === 0) {
346	        throw new Error('patron-anima collect requires a non-empty string "planId" given.');
347	      }
348	
349	      const book = getPlansBook();
350	      const plan = await book.get(planId);
351	      if (!plan) {
352	        throw new Error(`Plan "${planId}" not found.`);
353	      }
354	
355	      const stacks = guild().apparatus<StacksApi>('stacks');
356	      const sessionsBook = stacks.readBook<SessionDoc>('animator', 'sessions');
357	      const session = await sessionsBook.get(sessionId);
358	      const output = session?.output ?? '';
359	
360	      const reviewable = reviewableDecisions(plan);
361	      const emissionsByDecisionId = parseEmission(output, reviewable);
362	
363	      // Apply verdicts to each touched decision. Untouched decisions are
364	      // left unfilled — decision-review will surface them to the human.
365	      const touched: string[] = [];
366	      const decisions = (plan.decisions ?? []).map(d => ({ ...d }));
367	      for (const decision of decisions) {
368	        const emission = emissionsByDecisionId.get(decision.id);
369	        if (!emission) continue;
370	        decision.patron = emission;
371	        decision.selected = emission.selection;
372	        delete decision.patronOverride;
373	        touched.push(decision.id);
374	      }
375	
376	      await book.patch(planId, {
377	        decisions,
378	        updatedAt: new Date().toISOString(),
379	      });
380	
381	      return {
382	        sessionId,
383	        touchedDecisionIds: touched,
384	        totalReviewable: reviewable.length,
385	      };
386	    },
387	  };
388	}
