#!/usr/bin/env -S node --experimental-transform-types
/**
 * Build a patron-anima prompt covering ALL decisions on a plandoc (not just
 * the reviewable subset). Writes the prompt to stdout. Pair with
 * `nsg summon --role patron --prompt "$(build-seeall-prompt.ts <planId>)"`.
 *
 * Mirrors buildPatronPrompt() in
 *   /workspace/nexus/packages/plugins/astrolabe/src/engines/patron-anima.ts
 * but drops the reviewable filter.
 */

import { execFileSync } from 'node:child_process';
import { readFileSync } from 'node:fs';

const PROMPT_TEMPLATE = readFileSync(
  '/workspace/nexus/packages/plugins/astrolabe/patron-anima-prompt.md',
  'utf-8',
);

interface Decision {
  id: string;
  question: string;
  context?: string;
  options: Record<string, string>;
  recommendation?: string;
  rationale?: string;
  selected?: string;
}

interface PlanDoc {
  decisions?: Decision[];
}

function buildPatronPrompt(decisions: Decision[]): string {
  const lines: string[] = [];
  for (const d of decisions) {
    lines.push(`### ${d.id}: ${d.question}`);
    if (d.context) {
      lines.push('');
      lines.push(`Context: ${d.context}`);
    }
    lines.push('');
    lines.push('Options:');
    for (const [key, label] of Object.entries(d.options)) {
      lines.push(`- \`${key}\` — ${label}`);
    }
    if (d.recommendation) {
      lines.push('');
      const recLabel = d.options[d.recommendation] ?? d.recommendation;
      lines.push(
        `Analyst recommendation: \`${d.recommendation}\` (${recLabel})`,
      );
      if (d.rationale) {
        lines.push(`Analyst rationale: ${d.rationale}`);
      }
    } else {
      lines.push('');
      lines.push('Analyst recommendation: (none — you must fill in)');
    }
    lines.push('');
  }
  const block = lines.join('\n').replace(/\n+$/, '');
  return PROMPT_TEMPLATE.replace('{{DECISIONS}}', block);
}

const planId = process.argv[2];
if (!planId) {
  console.error('usage: build-seeall-prompt.ts <planId>');
  process.exit(1);
}

const raw = execFileSync('nsg', ['plan', 'show', planId], {
  encoding: 'utf-8',
  maxBuffer: 32 * 1024 * 1024,
});
const plan: PlanDoc = JSON.parse(raw);
const decisions = plan.decisions ?? [];
if (decisions.length === 0) {
  console.error(`plan ${planId} has no decisions`);
  process.exit(1);
}

process.stdout.write(buildPatronPrompt(decisions));

